import{_ as i,o as p,c as a,ag as e}from"./chunks/framework.DXGyWiRo.js";const t="/assets/image-20251113212523906.CkR7zFeK.png",g=JSON.parse('{"title":"编辑器","description":"","frontmatter":{},"headers":[],"relativePath":"ES/工具链/编辑器.md","filePath":"ES/工具链/编辑器.md","lastUpdated":null}'),r={name:"ES/工具链/编辑器.md"};function s(n,l,o,h,d,c){return p(),a("div",null,[...l[0]||(l[0]=[e('<h1 id="编辑器" tabindex="-1">编辑器 <a class="header-anchor" href="#编辑器" aria-label="Permalink to &quot;编辑器&quot;">​</a></h1><h3 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h3><p>不管你写什么代码你都须要编辑器来帮你编辑文本，一个优秀的编辑器能够跟大程度上提高开发效率，甚至影响写代码时的心情。</p><h3 id="vscode" tabindex="-1">VScode <a class="header-anchor" href="#vscode" aria-label="Permalink to &quot;VScode&quot;">​</a></h3><p>非常强大的现代化编辑器，拥有现代的UI界面和大量的的插件支持，通过配置工具链可以进行多方面的开发。</p><p><a href="https://zhuanlan.zhihu.com/p/17864898987" target="_blank" rel="noreferrer">(26 封私信 / 81 条消息) 【VS Code】VSCode设置代理模式 - 知乎</a></p><p>推荐方法二：<a href="https://blog.csdn.net/qq_41679061/article/details/132448137" target="_blank" rel="noreferrer">修改『Visual Studio Code（VS Code）』插件默认安装路径的方法_vscode修改插件安装路径-CSDN博客</a></p><p>插件：</p><p>在VScode上进行单片机开发：<a href="https://em-ide.com/zh-cn/docs/intro/" target="_blank" rel="noreferrer">EIDE</a></p><p><img src="'+t+`" alt="image-20251113212523906"></p><h3 id="vim" tabindex="-1">Vim <a class="header-anchor" href="#vim" aria-label="Permalink to &quot;Vim&quot;">​</a></h3><p>无需多言，编辑器之神。只需要通过键盘就能完成所有操作，同时轻量化的设计可以让它在许多资源受限的平台运行。</p><h4 id="获取" tabindex="-1">获取： <a class="header-anchor" href="#获取" aria-label="Permalink to &quot;获取：&quot;">​</a></h4><p>Linux平台一般自带Vim，如果没有也可以通过包管理工具轻松获得。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt install vim  #Ubantu</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sudo yum install vim  #Centos</span></span></code></pre></div><p>Windows平台下载：<a href="https://www.vim.org/download.php" target="_blank" rel="noreferrer">下载 ： Vim Online</a></p><h4 id="使用方法" tabindex="-1">使用方法： <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法：&quot;">​</a></h4><p>vim编辑器有如下几个模式：</p><ul><li><p>普通模式 用来浏览文本</p></li><li><p>命令模式 用来输入命令进入其他模式或者保存退出</p></li><li><p>插入模式 用来编辑文本</p></li><li><p>预览模式 用来选中文本</p></li></ul><h5 id="命令模式下的常用命令" tabindex="-1">命令模式下的常用命令 <a class="header-anchor" href="#命令模式下的常用命令" aria-label="Permalink to &quot;命令模式下的常用命令&quot;">​</a></h5><p><strong>光标移动：</strong></p><ul><li><p>H向左</p></li><li><p>J向下</p></li><li><p>K向上</p></li><li><p>L向右</p></li></ul><p><strong>其他操作：</strong></p><ul><li><p>shift+g 光标移至到文件最后</p></li><li><p>gg 光标移至文件最前</p></li><li><p>w写入</p></li><li><p>i 光标位置前的字母位置插入</p></li><li><p>a 光标位置后的字母插入</p></li><li><p>o 直接进入下一行</p></li><li><p>x删除光标所在位置的字母</p></li><li><p>dd删除光标所在行</p></li><li><p>dw 删除光标所在单词</p></li><li><p>u撤销命令</p></li></ul><p><strong>ps.vim中删除相当于剪切被删除的内容被暂存在缓存区中可以通过P命令粘贴</strong></p><p><strong>翻页</strong></p><ul><li><p>ctrl B 上翻页</p></li><li><p>ctrl F 下翻页</p></li><li><p>ctrl E 滚动形式下翻</p></li><li><p>ctrl Y 滚动向上翻</p></li></ul><p><strong>字母跳跃</strong></p><ul><li><p>b跳跃到当前光标所在单词的首字母</p></li><li><p>e跳跃到当前光标所在单词的最后一个字母</p></li><li><p>w跳跃到下一个单词的首字母然后再跳跃到这个单词的最后</p></li></ul><p>ps.上面三个字母跳跃的命令都可以搭配shift使用实现大幅度的跳跃</p><p><strong>行段跳越</strong></p><ul><li><p>shift + 6 跳跃到本行的开头（0也是）</p></li><li><p>shfit + 4 跳跃到本行的结尾</p></li><li><p>按{或者}跳跃函数段落</p></li></ul><p><strong>复制粘贴</strong></p><ul><li><p>p粘贴</p></li><li><p>yw 复制当前的单词</p></li><li><p>y$从当前单词复制到末尾</p></li><li><p>y+数字 表示从当前位置开始要复制的行数</p></li></ul><h5 id="可视化模式操作" tabindex="-1">可视化模式操作 <a class="header-anchor" href="#可视化模式操作" aria-label="Permalink to &quot;可视化模式操作&quot;">​</a></h5><ul><li><p>小v进入可视化模式进行文本选择</p></li><li><p>V进入可视化模式按行选择</p></li><li><p>ctrl v 矩阵化选择</p></li><li><p>在可视化模式中o 跳转到选中区域的开始位置或者最后位置</p></li><li><p>0补全角落</p></li><li><p>vaw选中单词</p></li><li><p>vab 选中小括号中的内容</p></li><li><p>vaB 选中大括号中的内容</p></li><li><p>va&lt;包含尖括号 删除</p></li><li><p>v shift + &lt; &gt; 代码缩进</p></li><li><p>v shift + ~ 字母大小写取反</p></li><li><p>v+u 全部转化为小写</p></li><li><p>v+U 全部转化为大写</p></li></ul><h5 id="查找和替换" tabindex="-1"><strong>查找和替换</strong> <a class="header-anchor" href="#查找和替换" aria-label="Permalink to &quot;**查找和替换**&quot;">​</a></h5><p>普通模式下输入 /+要查找的字符串 光标便会自动跳转到第一个匹配的字符，按n跳转到下一个匹配字符，N跳转上一个匹配字符</p><ul><li><p>：s/要替换的字符/要替换成的字符/g 光标的所在行中的目标字符都被替换</p></li><li><p>：%s/要替换的字符/要替换成的字符/g 整个文件的目标字符都被替换</p></li><li><p>：起始行，终止行s/要替换的字符/g 选中行进行字符替换</p></li></ul><p>g后面+c每次替换都询问是否要替换</p>`,40)])])}const m=i(r,[["render",s]]);export{g as __pageData,m as default};
